import { useEffect, useMemo, useState } from 'react';
import Navbar from '../shared/Navbar';
import Footer from '../shared/Footer';
import { spaces } from '../data/spaces';
import SpaceCard from '../components/SpaceCard';

export default function Favorites() {
  const [favoriteIds, setFavoriteIds] = useState([]);
  useEffect(() => {
    try {
      const raw = localStorage.getItem('wn:favorites');
      setFavoriteIds(raw ? JSON.parse(raw) : []);
    } catch {
      setFavoriteIds([]);
    }
  }, []);

  const list = useMemo(() => spaces.filter((s) => favoriteIds.includes(s.id)), [favoriteIds]);

  return (
    <div className="min-h-screen flex flex-col bg-white">
      <Navbar />
      <main className="flex-1 w-full px-6 md:px-12 lg:px-16 py-10">
        <div className="flex items-center justify-between gap-4">
          <h2 className="text-2xl font-bold text-gray-900">Saved spaces</h2>
          <div className="text-sm text-gray-600">{list.length} saved</div>
        </div>
        {list.length === 0 ? (
          <div className="mt-10 text-gray-600">No saved spaces yet. Explore and click Save on any workspace.</div>
        ) : (
          <div className="mt-6 grid grid-cols-1 md:grid-cols-3 gap-6">
            {list.map((s) => (
              <SpaceCard key={s.id} space={s} />
            ))}
          </div>
        )}
      </main>
      <Footer />
    </div>
  );
}
